howItWorks.step1Code:
yourCenturion.understand({
  mission: 'yours',
  privacy: 'absolute',
  home: 'defined',
  leavesHome: false
})

// 이해했습니다 — 그리고 그것은 당신과 함께 있습니다.

howItWorks.step2Code:
yourCenturion.place({
  where: 'your home',
  outsideWorld: 'your choice',
  leaves: false
})

// 안정된. 아무 것도 방황하지 않습니다.

howItWorks.step3Code:
yourCenturion.live({
  always: true,
  learns: 'from you only',
  shares: 'nothing',
  companySees: 'nothing'
})

// 사적인. 충실한. 당신 것.

developers.code1:
// Skills from other people are not trusted
skill.fromSomeoneElse({
  trust: 'none',
  risk: 'stolen secrets | hidden behaviour'
})

// Centurion will not install
// a stranger's skill on your say-so alone.

developers.code2:
centurion.makeSkill({
  for: 'what you actually need',
  basedOn: 'your life's mission',
  author: 'your Centurion'
})

// It builds skills. It does not
// shop for skills in a store.

developers.code3:
work.continues({
  gap: 'found',
  skill: 'made now',
  stays: 'with you'
})

// Skills appear when they are needed —
// and stay in your home, under your control.

developers.code4:
loop.run({
  notice: true,
  act: true,
  learn: true,
  improve: true
})

// Notice. Act. Learn. Improve.
// Skills get better with use —
// without reporting home.

